import sys
from collections import deque

class Solution:
    def isCompleteTree(self, root: TreeNode) -> bool:
        if not root: return True

        queue = deque()
        queue.append(root)

        while queue:
            node = queue.popleft()
            if node:
                queue.append(node.left)
                queue.append(node.right)
            else:
                return False

        return True


