#include <iostream>
#include <vector>
#include <utility>
using namespace std;

// Definition for a binary tree node.
struct TreeNode {
   int val;
   TreeNode *left;
   TreeNode *right;
   TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    bool isCompleteTree(TreeNode* root) {
        if (!root) return true;

        queue<TreeNode*> q;
        q.push(root);

        bool hasNonLeaf = false;
        bool hasLeaf = false;

        while (!q.empty()) {
            TreeNode* node = q.front(); q.pop();

            if (node) {
                if (node->left) {
                    q.push(node->left);
                } else {
                    hasLeaf = true;
                }

                if (node->right) {
                    q.push(node->right);
                } else {
                    hasLeaf = true;
                }
            } else {
                hasNonLeaf = true;
            }

            if (hasNonLeaf && hasLeaf) return false;
        }

        return true;
    }
};
